const enabled = $env.N8N_WORKFLOW_SLO_MONITOR_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: true, reason: 'kill_switch_disabled' } }];
}
const requestId = 'ops-slo-monitor-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = 'n8n-slo-monitor-' + new Date().toISOString().slice(0, 16);
const crypto = require('crypto');
const payloadHash = crypto.createHash('sha256').update(JSON.stringify({ action: 'ops.slo_monitor', ts: new Date().toISOString().slice(0, 16) })).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(requestId + 'ops.slo_monitor' + payloadHash).digest('hex');
return [{ json: { killed: false, requestId, correlationId, idempotencyKey, timestamp: new Date().toISOString() } }];

const calls = $input.all().map(i => i.json);
const flat = Array.isArray(calls[0]) ? calls[0] : calls;
const validCalls = flat.filter((call) => call && (call.started_at || call.completed_at || call.status || call.error_code));
if (validCalls.length === 0) {
  return [{ json: { breach: false, noData: true, robotStatus: 'partial', p95: 0, errorRate: 0, totalCalls: 0, sloP95: 5000, sloErrorRate: 5, summary: 'No provider calls in the last 5 minutes' } }];
}
const durations = validCalls.map((call) => {
  const started = Date.parse(call.started_at || '');
  const completed = Date.parse(call.completed_at || '');
  if (Number.isFinite(started) && Number.isFinite(completed) && completed >= started) {
    return completed - started;
  }
  return 0;
}).sort((a, b) => a - b);
const p95Index = Math.max(0, Math.ceil(durations.length * 0.95) - 1);
const p95 = durations[p95Index] || 0;
const failed = validCalls.filter((call) => ['failed', 'partial', 'canceled', 'timeout'].includes(String(call.status || '').toLowerCase())).length;
const errorRate = validCalls.length ? (failed / validCalls.length) * 100 : 0;
const SLO_P95_MS = 5000;
const SLO_ERROR_RATE = 5;
const breach = p95 > SLO_P95_MS || errorRate > SLO_ERROR_RATE;
const robotStatus = breach ? 'failed' : 'passed';
const roundedErrorRate = Math.round(errorRate * 100) / 100;
const summary = breach
  ? `SLO breach detected: p95=${p95}ms error_rate=${roundedErrorRate}% calls=${validCalls.length}`
  : `SLO healthy: p95=${p95}ms error_rate=${roundedErrorRate}% calls=${validCalls.length}`;
return [{ json: { breach, noData: false, robotStatus, p95, errorRate: roundedErrorRate, totalCalls: validCalls.length, sloP95: SLO_P95_MS, sloErrorRate: SLO_ERROR_RATE, summary } }];

const crypto = require('crypto');
const prep = $('Kill Switch + Prep').item.json;
const payload = {
  id: prep.requestId,
  env: $env.ASPIRE_ROBOT_ENV || 'production',
  suite: $env.ASPIRE_ROBOT_SUITE || 'aspire_robots',
  status: $json.robotStatus || 'passed',
  startedAt: prep.timestamp || new Date().toISOString(),
  finishedAt: new Date().toISOString(),
  versionRef: ($env.ASPIRE_ROBOT_VERSION_REF || 'n8n-live') + ':slo-monitor',
  summary: $json.summary || 'SLO monitor completed',
  scenarios: [{
    name: 'slo_window',
    status: $json.robotStatus || 'passed',
    summary: $json.summary || 'SLO monitor completed',
    evidence: [
      `correlation:${prep.correlationId}`,
      `total_calls:${$json.totalCalls || 0}`,
      `p95_ms:${$json.p95 || 0}`,
      `error_rate:${$json.errorRate || 0}`
    ]
  }],
  meta: { workflow: 'slo-monitor', correlationId: prep.correlationId, requestId: prep.requestId, totalCalls: $json.totalCalls || 0, p95Ms: $json.p95 || 0, errorRate: $json.errorRate || 0, noData: Boolean($json.noData) }
};
const robotBody = JSON.stringify(payload);
const robotSignature = crypto.createHmac('sha256', $env.ASPIRE_ROBOT_S2S_SECRET).update(robotBody).digest('hex');
return [{ json: { ...$json, robotBody, robotSignature } }];

